ey-light-2 u-map u-map-1\">\n          <div class=\"embed-responsive\">\n            <iframe class=\"embed-responsive-item\" src=\"https://maps.google.com/maps?output=embed&amp;q=N%C5%AF%C5%A1a%C5%99sk%C3%A1%204374%2C%0A276%2001%20M%C4%9Bln%C3%ADk&amp;z=16&amp;t=m\" data-map=\"\"></iframe>\n          </div>\n        </div>\n        <p class=\"u-text u-text-1\">\n          <span style=\"font-weight: 700;\"> Telefon </span>\n          <br>Klára Bártová&nbsp;<a href=\"tel:+420737246163\" class=\"u-active-none u-border-none u-btn u-button-link u-button-style u-hover-none u-none u-text-palette-1-base u-btn-1\">+420 737 246 163</a>\n          <br>vzorková prodejna <br>\n          <span style=\"font-weight: 700;\">\n            <br>Adresa \n          </span>\n          <br>Nůšařská 4374<br>276 01 Mělník <span style=\"font-weight: 700;\">\n            <br>\n            <br>Email \n          </span>\n          <br>\n          <a href=\"mailto:info@interieryhoryna.cz?subject=Poptávka z webu\" class=\"u-active-none u-border-none u-btn u-button-link u-button-style u-hover-none u-none u-text-palette-1-base u-btn-2\">info@interieryhoryna.cz </a>\n          <br>Parkování v areálu <span style=\"font-weight: 700;\">\n            <br>\n            <br>Otevírací hodiny \n          </span>\n          <br>Pondělí - Pátek 8 - 17<br>Sobota - Neděle: po telefonické domluvě <br>\n          <br>\n          <span style=\"font-weight: 700;\">Možnost platby kartou.&nbsp;</span>\n          <br>\n        </p>\n        <editor-squiggler style=\"height: 0px; width: 0px;\">\n          <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n          <div class=\"ms-editor-squiggler\"></div>\n        </editor-squiggler>\n        <editor-squiggler style=\"height: 0px; width: 0px;\">\n          <style> @media print {