1\":true,\"color_palette-1-base\":true,\"color_palette-2\":true,\"color_palette-2-base\":true,\"color_grey\":true,\"color_white\":true,\"color_black\":true,\"color_grey-10\":true}'),(365,73,'page_keywords','​A Leader in Solar, ​Energy Freedom with Solar and Storage, ​Simplified project development for a complex world, ​Make solar project development easier from start to finish, Why we should be greening our homes with plants, ​Energy Freedom with Solar and Storage, ​Help change the world, Get In Touch'),(366,73,'page_description',''),(367,73,'page_canonical',''),(368,73,'page_metaTags',''),(369,73,'page_metaGeneratorContent',''),(370,73,'page_metaReferrer',''),(371,73,'page_customHeadHtml',''),(372,73,'page_title','Kuchyně'),(373,73,'formsData','[]'),(374,73,'_edit_lock','1708702512:2'),(402,73,'_edit_last',1),(403,73,'_wp_page_template','default'),(439,83,'_np_template','html'),(440,83,'_np_publish_html','\n    \n    <section class=\"u-align-center u-clearfix u-white u-section-2\" id=\"carousel_2dec\">\n      <h2 class=\"u-align-center u-text u-text-1\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\">Stínící technika ​CLIMAX a VELUX</h2>\n      <p class=\"u-align-center u-hidden u-text u-text-default u-text-2\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"500\">Our Company&nbsp;offer unprecendented value, reliability, and support to project partners. </p>\n      <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-layout-wrap-1\">\n        <div class=\"u-layout\" style=\"\">\n          <div class=\"u-layout-col\" style=\"\">\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-1\" data-image-width=\"2048\" data-image-height=\"1365\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"250\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/uvondi.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-1\"></div>\n                </div>\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-size-30 u-white u-layout-cell-2\">\n                  <div class=\"u-container-layout u-container-layout-2\">\n                    <h3 class=\"u-align-left u-text u-text-3\"> Široká nabídka značek ​Climax a Velux</h3>\n                    <p class=\"u-align-left u-text u-text-4\"> Naše interiérové studio nabízí stínící techniku prvotřídních značek CLIMAX a VELUX, která je vyrobena z kvalitních materiálů a dodává vašemu domovu nebo pracovnímu prostoru skvělý vzhled a funkčnost. Ať už si přejete moderní minimalistický design nebo klasický a elegantní vzhled, naše stínící technika vám umožní dosáhnout požadované atmosféry.&nbsp;<br>\n                    </p>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                  </div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-palette-2-base u-size-30 u-layout-cell-3\">\n                  <div class=\"u-container-layout u-container-layout-3\">\n                    <h3 class=\"u-align-left u-text u-text-5\"> Typy stínící techniky:</h3>\n                    <ul class=\"u-align-left u-text u-text-6\">\n                      <li>Venkovní a v