u-layout-col\" style=\"\">\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-1\" data-image-width=\"866\" data-image-height=\"1155\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"250\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/uvodni-3.jpeg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-1\"></div>\n                </div>\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-size-30 u-white u-layout-cell-2\">\n                  <div class=\"u-container-layout u-container-layout-2\">\n                    <h3 class=\"u-align-left u-text u-text-3\">Nábytek na míru</h3>\n                    <p class=\"u-align-left u-text u-text-4\">\n                      <br>Zabýváme se výrobou nábytku na míru jako jsou\nvestavěné skříně, koupelnový nábytek, vybavení dětských pokojů a kancelářských\nprostor. Při výrobě používáme pouze kvalitní a ověřené materiály.&nbsp;<br>\n                    </p>\n                  </div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-palette-2-base u-size-30 u-layout-cell-3\">\n                  <div class=\"u-container-layout u-container-layout-3\">\n                    <h3 class=\"u-align-left u-text u-text-5\">Vyhovíme Vašim představám<br>\n                      <br>\n                    </h3>\n                    <p class=\"u-align-left u-text u-text-6\"> Vyrobíme pro vás funkční nábytek dle Vašich představ, a to bez ohledu na to, zda preferujete moderní a minimalistický design, rustikální atmosféru nebo elegantní klasiku.&nbsp;<br>\n                    </p>\n                  </div>\n                </div>\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-2\" data-image-width=\"1440\" data-image-height=\"1080\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"500\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/11/IMG_5200.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-4\"></div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-20\" style=\"\">\n              <div class=\"u-layout-row\" style=\"\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-3\" data-image-width=\"1536\" data-image-height=\"2304\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"750\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/IMG_0239.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-5\"></div>\n                </div>\n                <div class=\"u-black u-container-align-left u-container-style u-layout-cell u-size-30 u-layout-cell-6\">\n                  <div class=\"u-container-layout u-container-layout-6\">\n                    <h3 class=\"u-align-left u-text u-text-7\">\n                      <br> Jaký nábytek na míru pro Vás vyrobíme?<br>\n                      <br>\n                    </h3>\n                    <ul class=\"u-align-left u-text u-text-8\">\n                      <li>\n                        <span style=\"font-size: 1.125rem; background-color: #000000; color: #ffffff; font-family: Montserrat,sans-serif;\">Vestavěné skříně na míru</span>\n                      </li>\n                      <li>Koupelnový nábytek</li>\n                      <li>Vybavení dětských pokojů</li>\n                      <li>Vybavení kancelář