emplates\" data-jm-back-link-title=\"Joomla Template\" data-created-with-link=\"https://nicepage.com/static-site-generator\" data-created-with-title=\"Static Site Generator\" data-wp-created-with-link=\"https://nicepage.com/wordpress-website-builder\" data-wp-created-with-title=\"WordPress Website Builder\" data-jm-created-with-link=\"https://nicepage.com/joomla-page-builder\" data-jm-created-with-title=\"Joomla Template Creator\" data-app-version=\"6.5.3\">\n    \n    <section class=\"u-align-center u-clearfix u-white u-block-270b-1\" custom-posts-hash=\"[[I,T],[I,T],[I,T]]\" data-section-properties=\"{&quot;margin&quot;:&quot;none&quot;,&quot;stretch&quot;:true}\" data-id=\"270b\" data-posts-content=\"[{\'images\':[[339,192]],\'maps\':[],\'videos\':[],\'icons\':[],\'textWidth\':1140,\'textHeight\':837,\'id\':1,\'groupId\':2,\'headingProp\':\'h4\',\'textProp\':\'text\'},{\'images\':[[339,192]],\'maps\':[],\'videos\':[],\'icons\':[],\'textWidth\':1140,\'textHeight\':837,\'id\':1,\'groupId\':2,\'headingProp\':\'h4\',\'textProp\':\'text\'},{\'images\':[[339,192]],\'maps\':[],\'videos\':[],\'icons\':[],\'textWidth\':1140,\'textHeight\':837,\'id\':1,\'groupId\':2,\'headingProp\':\'h4\',\'textProp\':\'text\'}]\" data-style=\"list-control-image-left\" id=\"carousel_2dec\" data-source=\"functional_fix\">\n      <h2 class=\"u-align-center u-text u-block-270b-20\" data-hover-preset-name=\"zoomIn\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" spellcheck=\"false\" data-ms-editor=\"true\">Výroba nábytku Horyna</h2>\n      <p class=\"u-align-center u-text u-text-default-lg u-text-default-md u-text-default-sm u-text-default-xl u-block-270b-21\" data-hover-preset-name=\"zoomIn\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"500\" spellcheck=\"false\" data-ms-editor=\"true\">​Vyrobíme pro vás funkční nábytek dle Vašich představ.&nbsp;<br></p>\n      <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-block-270b-22\">\n        <div class=\"u-layout\" style=\"\">\n          <div class=\"u-layout-col\" style=\"\">\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-block-270b-23\" data-image-width=\"866\" data-image-height=\"1155\" data-hover-preset-name=\"fadeIn\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"250\">\n                  <div class=\"u-container-layout u-block-270b-24\"></div>\n                </div>\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-size-30 u-white u-block-270b-25\">\n                  <div class=\"u-container-layout u-block-270b-26\">\n                    <h3 class=\"u-align-left u-text u-block-270b-27\">Nábytek na míru</h3>\n                    <p class=\"u-align-left u-text u-block-270b-28\"> ​<br>Zabýváme se výrobou nábytku na míru jako jsou\nvestavěné skříně, koupelnový nábytek, vybavení dětských pokojů a kancelářských\nprostor. Při výrobě používáme pouze kvalitní a ověřené materiály.&nbsp;<br></p>\n                    \n                  </div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-palette-2-base u-size-30 u-block-270b-39\">\n                  <div class=\"u-container-layout u-block-270b-40\">\n                    <h3 class=\"u-align-left u-text u-block-270b-41\">Vyhovíme Vašim představám<br><br></h3>\n                    <p class=\"u-align-left u-text u-block-270b-42\" spellcheck=\"false\" data-ms-editor=\"true\"> ​Vyrobíme pro vás funkční nábytek dle Vašich představ, a to bez ohledu na to, zda preferujete moderní a minimalistický design, rustikální atmosféru nebo elegantní klasiku.&nbsp;<br></p>\n                    \n                  </div>\n                </div>\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-block-270b-31\" data-image-width=\"1440\" data-image-height=\"1080\" data-hover-preset-name=\"fadeIn\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"500\">\n                  <div class=\"u-container-layout u-block-270b-32\"></div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-20\" style=\"\">\n              <div class=\"u-layout-row\" style=\"\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-block-270b-33\" data-image-width=\"1536\" data-image-height=\"2304\" data-hover-preset-name=\"fadeIn\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"750\">\n                  <div class=\"u-container-layout u-block-270b-34\"></div>\n                </div>\n                <div class=\"u-black u-container-align-left u-container-style u-layout-cell u-size-30 u-block-270b-45\">\n                  <div class=\"u-container-layout u-block-270b-46\">\n                    <h3 class=\"u-align-left u-text u-block-270b-47\" spellcheck=\"false\" data-ms-editor=\"true\"><br>​Jaký nábytek na míru pro Vás vyrobíme?<br><br></h3>\n                    <ul class=\"u-align-left u-text u-block-270b-48\" spellcheck=\"false\" data-ms-editor=\"true\"><li><div class=\"hidden u-list-icon u-block-270b-57\"></div><span style=\"font-size: var(--list-font-size); background-color: var(--black); color: var(--black-text-color); font-family: var(--text-font);\">Vestavěné skříně na míru</span></li><li>Koupelnový nábytek</li><li><div class=\"hidden u-list-icon u-block-270b-51\"></div>Vybavení dětských pokojů</li><li><div class=\"hidden u-list-icon u-block-270b-52\"></div>Vybavení kancelářských prostor</li><li><