n.u-xs .u-section-4 .u-image-3 {\n  margin-top: 156px;\n  margin-left: auto;\n}\n.u-xs .u-section-4 .u-image-4 {\n  margin-top: -179px;\n  margin-right: auto;\n}\n/*/RESPONSIVE_CLASS*/\n'),(468,86,'_np_body_class','u-body u-xl-mode'),(469,86,'_np_body_style',''),(470,86,'_np_body_data_bg',''),(471,86,'_np_hide_header','false'),(472,86,'_np_hide_footer','false'),(473,86,'_np_hide_backtotop',1),(474,86,'page_ogTags','{\"title\":\"\",\"description\":\"\",\"image\":\"\",\"url\":\"\"}'),(475,86,'_np_fonts','<link id=\"u-theme-google-font\" rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css?family=Montserrat:100,100i,200,200i,300,300i,400,400i,500,500i,600,600i,700,700i,800,800i,900,900i\">'),(476,86,'_np_backlink',''),(477,86,'dialogs','a:0:{}'),(478,86,'_np_site_style_css_used_ids','{\"color_palette-1\":true,\"color_palette-1-light-1\":true,\"color_palette-1-base\":true,\"color_palette-2\":true,\"color_palette-2-base\":true,\"color_white\":true,\"color_black\":true}'),(479,86,'page_keywords','​A Leader in Solar, ​Energy Freedom with Solar and Storage, ​Simplified project development for a complex world, ​Make solar project development easier from start to finish, Why we should be greening our homes with plants, ​Energy Freedom with Solar and Storage, ​Help change the world, Get In Touch'),(480,86,'page_description',''),(481,86,'page_canonical',''),(482,86,'page_metaTags',''),(483,86,'page_metaGeneratorContent',''),(484,86,'page_metaReferrer',''),(485,86,'page_customHeadHtml',''),(486,86,'page_title','Výroba'),(487,86,'formsData','[]'),(488,86,'_edit_lock','1708701892:2'),(489,89,'_np_template','html'),(490,89,'_np_publish_html','\n    \n    <section class=\"u-align-center u-clearfix u-white u-section-2\" id=\"carousel_2dec\">\n      <h2 class=\"u-align-center u-text u-text-1\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\">Podlahy Horyna</h2>\n      <p class=\"u-align-center u-text u-text-default u-text-2\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"500\"> Nabízíme široký výběr podlahových materiálů, které splní vaše nejnáročnější požadavky. </p>\n      <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-layout-wrap-1\">\n        <div class=\"u-layout\">\n          <div class=\"u-layout-col\">\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-1\" data-image-width=\"1920\" data-image-height=\"1080\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"250\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/uvodni-1.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-1\"></div>\n                </div>\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-size-30 u-white u-layout-cell-2\">\n                  <div class=\"u-container-layout u-container-layout-2\">\n                    <h3 class=\"u-align-left u-text u-text-3\">Co dokážeme nabídnout?</h3>\n                    <p class=\"u-align-left u-text u-text-4\"> Podlahy jsou základním prvkem každého interiéru a mají\nvýznamný vliv na celkový dojem z&nbsp;prostoru. Nabízíme velký výběr\npodlahových materiálů, které splní vaše nejnáročnější požadavky.<br>\n                    </p>\n                  </div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-style u-layout-cell u-palette-2-base u-size-30 u-layout-cell-3\">\n                  <div class=\"u-container-layout u-container-layout-3\">\n                    <h3 class=\"u-align-left u-text u-text-5\">V naší nabídce najdete</h3>\n                    <p class=\"u-align-left u-text u-text-6\"> Dřevěné podlahy</p>\n                    <p class=\"u-align-left u-text u-text-7\"> Přináší do místnosti příjemnou\natmosféru a přirozený vzhled. Nabízíme různé druhy dřevin a povrchové úpravy,\nabyste si mohli vybrat ten, který nejlépe ladí s Vaším stylem.<b></b>\n                    </p>\n                    <p class=\"u-align-left u-text u-text-8\"> Koberce&nbsp;</p>\n                    <p class=\"u-align-left u-text u-text-9\"> Pro zvýšení komfortu a akustiky v&nbsp;místnosti jsou\nkoberce vynikající volbou. Najdete u nás koberce různých materiálů, barev a\nvzorů, které osvěží váš prostor.<br>\n                      <br>\n                    </p>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                  </div>\n                </div>\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-2\" data-image-width=\"720\" data-image-height=\"721\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"500\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/08/PUCL40080_Interior09_Paintable-skirting_white_720x720.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-4\"></div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-20\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-3\" data-image-width=\"1400\" data-image-height=\"840\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"750\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/08/ImageTextBlock_bedroom_QuickStep_1920x1152.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-5\"></div>\n                </div>\n                <div class=\"u-black u-container-align-left u-container-style u-layout-cell u-size-30 u-layout-cell-6\">\n                  <div class=\"u-container-layout u-container-layout-6\">\n                    <p class=\"u-align-left u-text u-text-10\"><b>Laminátové\npodlahy</b>\n                    </p>\n                    <p class=\"u-align-left u-text u-text-11\"> Skvělá volba pro ty, kteří hledají\ncenově dostupnou a odolnou alternativu dřeva. Laminátové podlahy se vyznačují\nsnadnou údržbou a širokou paletou designů. Jsme partnerem prvotřídního výrobce\nznačky<br>Quick-Step.<br>\n                    </p>\n                    <editor-squiggler style=\"height: 0px; width: 0px; margin-bottom: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <p class=\"u-align-left u-text u-text-12\"><b>Linoleum –\nMarmoleum</b>\n                    </p>\n                    <editor-squiggler style=\"height: 0px; width: 0px; margin-bottom: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <p class=\"u-align-left u-text u-text-13\"> Ekologická linoleová podlaha vyrobená\nz přírodních a obnovitelných materiálů. Marmoleum je hypoalergenní, odolné\nproti opotřebení a snadno se udržuje.&nbsp;</p>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n      \n    </section>\n    <section class=\"u-align-center u-clearfix u-valign-top-xl u-white u-section-3\" id=\"carousel_6c5f\">\n      <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-layout-wrap-1\">\n        <div class=\"u-layout\" style=\"\">\n          <div class=\"u-layout-col\" style=\"\">\n            <div class=\"u-size-30\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-size-30 u-white u-layout-cell-1\">\n                  <div class=\"u-container-layout u-container-layout-1\">\n                    <p class=\"u-align-left u-text u-text-1\"><b>PVC</b>\n                    </p>\n                    <p class=\"u-align-left u-text u-text-2\"> Podlahové krytiny v&nbsp;rolích s&nbsp;vysokou\nodolností vůči opotřebení. Snadno se udržují, mají širokou paletu designů a\njsou cenově dostupné. Zakoupíte u nás produkty známých výrobců jako jsou Breno a Gerflor.&nbsp;&nbsp;<br>\n                    </p>\n                    <editor-squiggler style=\"height: 0px; width: 0px; margin-bottom: 0px; margin-left: 0px; margin-right: auto;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <p class=\"u-align-left u-text u-text-3\"><b>Vinylové podlahy</b>\n                    </p>\n                    <p class=\"u-align-left u-text u-text-4\"> Moderní a praktická volba pro různé\nprostory. Vinylové podlahy jsou odolné proti vlhkosti a snadno se udržují. Díky\nrůzným dekorům a vzorům můžete vytvořit unikátní vzhled. Nabízíme ty\nnejkvalitnější podlahy značek Quick-Step, ​Gerflor, Fatra a&nbsp;Moduelo.</p>\n                    <editor-squiggler style=\"height: 0px; width: 0px; margin-left: 0px; margin-right: auto;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                  </div>\n                </div>\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-1\" data-image-width=\"1920\" data-image-height=\"1080\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1000\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/QSSPRAYMOP_CleaningMop03_1920x1080.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-2\"></div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-30\" style=\"\">\n              <div class=\"u-layout-row\" style=\"\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-2\" data-image-width=\"2000\" data-image-height=\"1335\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"750\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/11/1-183961794.jpg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-3\"></div>\n                </div>\n                <div class=\"u-black u-container-align-left u-container-style u-layout-cell u-size-30 u-layout-cell-4\">\n                  <div class=\"u-container-layout u-container-layout-4\">\n                    <h3 class=\"u-align-left u-text u-text-5\">\n                      <br> Vyrovnání podkladu\n                    </h3>\n                    <p class=\"u-align-left u-text u-text-6\">Základem každé podlahy je kvalitní a rovný\npodklad. Vyrovnání podkladu spočívá v&nbsp;pečlivé přípravě a použití\nvyrovnávacích – nivelačních hmot. Při důsledném dodržení technologických\npostupů daných materiálů. Používáme pouze kvalitní a ověření materiály značek\nBOSTIK a UZIN.&nbsp;&nbsp;</p>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n      \n    </section>\n    <section class=\"u-clearfix u-white u-section-4\" id=\"carousel_5141\">\n      <div class=\"u-clearfix u-sheet u-sheet-1\">\n        <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-layout-wrap-1\">\n          <div class=\"u-gutter-0 u-layout\">\n            <div class=\"u-layout-row\">\n              <div class=\"u-container-style u-layout-cell u-size-20-lg u-size-20-xl u-size-30-md u-size-30-sm u-size-30-xs u-layout-cell-1\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"750\">\n                <div class=\"u-border-13 u-border-no-bottom u-border-no-left u-border-no-top u-border-palette-2-base u-container-layout u-valign-middle u-container-layout-1\">\n                  <h2 class=\"u-text u-text-default u-text-1\">Renovace podlah</h2>\n                </div>\n              </div>\n              <div class=\"u-align-left u-container-style u-layout-cell u-size-20-lg u-size-20-xl u-size-30-md u-size-30-sm u-size-30-xs u-layout-cell-2\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"250\">\n                <div class=\"u-container-layout u-container-layout-2\">\n                  <p class=\"u-text u-text-2\">Renovace podlah je proces obnovy a vylepšení stávající\npodlahové krytiny. Převážně se jedná o dřevěné a parketové podlahy. Obnova\nspočívá v&nbsp;obroušení původních poškozených nebo opotřebených povrchů a\nnásledném lakování nebo olejování pomocí laků a přírodních olejů značek BONA a\nPALLMAN.</p>\n                  <p class=\"u-text u-text-default u-text-3\"> &nbsp;</p>\n                  <editor-squiggler style=\"height: 0px; width: 0px;\">\n                    <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                    <div class=\"ms-editor-squiggler\"></div>\n                  </editor-squiggler>\n                </div>\n              </div>\n              <div class=\"u-container-style u-image u-layout-cell u-size-