scale(1) !important\n}\n</style>\n      \n      \n    </section><section class=\"u-align-center u-clearfix u-valign-top-xl u-white u-block-0f6e-1\" custom-posts-hash=\"[[I,T],[I,T],[I,T]]\" data-section-properties=\"{&quot;margin&quot;:&quot;none&quot;,&quot;stretch&quot;:true}\" data-id=\"0f6e\" data-posts-content=\"[{\'images\':[[339,192]],\'maps\':[],\'videos\':[],\'icons\':[],\'textWidth\':1140,\'textHeight\':837,\'id\':1,\'groupId\':2,\'headingProp\':\'h4\',\'textProp\':\'text\'},{\'images\':[[339,192]],\'maps\':[],\'videos\':[],\'icons\':[],\'textWidth\':1140,\'textHeight\':837,\'id\':1,\'groupId\':2,\'headingProp\':\'h4\',\'textProp\':\'text\'},{\'images\':[[339,192]],\'maps\':[],\'videos\':[],\'icons\':[],\'textWidth\':1140,\'textHeight\':837,\'id\':1,\'groupId\':2,\'headingProp\':\'h4\',\'textProp\':\'text\'}]\" data-style=\"list-control-image-left\" id=\"carousel_6c5f\" data-source=\"functional_fix\">\n      \n      \n      <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-block-0f6e-22\">\n        <div class=\"u-layout\" style=\"\">\n          <div class=\"u-layout-col\" style=\"\">\n            <div class=\"u-size-30\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-size-30 u-white u-block-0f6e-25\" data-hover-preset-name=\"fadeIn\">\n                  <div class=\"u-container-layout u-block-0f6e-26\">\n                    <p class=\"u-align-left u-text u-block-0f6e-27\" spellcheck=\"false\" data-ms-editor=\"true\"> ​<b>PVC</b></p>\n                    <p class=\"u-align-left u-text u-block-0f6e-28\" spellcheck=\"false\" data-ms-editor=\"true\"> ​Podlahové krytiny v&nbsp;rolích s&nbsp;vysokou\nodolností vůči opotřebení. Snadno se udržují, mají širokou paletu designů a\njsou cenově dostupné. Zakoupíte u nás produkty známých výrobců jako jsou Breno a Gerflor.&nbsp;&nbsp;<br></p>\n                    \n                  <editor-squiggler style=\"height: 0px; width: 0px; margin-bottom: 0px; margin-left: 0px; margin-right: auto;\"><style>\n  @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style><div class=\"ms-editor-squiggler\"></div></editor-squiggler><p class=\"u-align-left u-text u-block-0f6e-60\" spellcheck=\"false\" data-ms-editor=\"true\">​<b>Vinylové podlahy</b></p><p class=\"u-align-left u-text u-block-0f6e-61\" spellcheck=\"false\" data-ms-editor=\"true\">​Moderní a praktická volba pro různé\nprostory. Vinylové podlahy jsou odolné proti vlhkosti a snadno se udržují. Díky\nrůzným dekorům a vzorům můžete vytvořit unikátní vzhled. Nabízíme ty\nnejkvalitnější podlahy značek Quick-Step, ​Gerflor, Fatra a&nbsp;Moduelo.</p><editor-squiggler style=\"height: 0px; width: 0px; margin-left: 0px; margin-right: auto;\"><style>\n  @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style><div class=\"ms-editor-squiggler\"></div></editor-squiggler><editor-squiggler style=\"height: 0px; width: 0px;\"><style>\n  @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style><div class=\"ms-editor-squiggler\"></div></editor-squiggler><editor-squiggler style=\"height: 0px; width: 0px;\"><style>\n  @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style><div class=\"ms-editor-squiggler\"></div></editor-squiggler><editor-squig