tml',''),(511,89,'page_title','Podlahy'),(512,89,'formsData','[]'),(513,89,'_edit_lock','1708702664:2'),(514,92,'_np_template','html'),(515,92,'_np_publish_html','\n    \n    <section class=\"u-clearfix u-white u-section-2\" id=\"carousel_5141\">\n      <div class=\"u-clearfix u-sheet u-valign-bottom u-sheet-1\">\n        <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-layout-wrap-1\">\n          <div class=\"u-gutter-0 u-layout\">\n            <div class=\"u-layout-row\">\n              <div class=\"u-container-style u-layout-cell u-size-15-lg u-size-15-xl u-size-30-md u-size-30-sm u-size-30-xs u-layout-cell-1\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"750\">\n                <div class=\"u-border-13 u-border-no-bottom u-border-no-left u-border-no-top u-border-palette-2-base u-container-layout u-container-layout-1\">\n                  <h2 class=\"u-text u-text-1\">O nás</h2>\n                </div>\n              </div>\n              <div class=\"u-align-left u-container-style u-layout-cell u-size-19-lg u-size-19-xl u-size-30-md u-size-30-sm u-size-30-xs u-layout-cell-2\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"250\">\n                <div class=\"u-container-layout u-container-layout-2\">\n                  <p class=\"u-text u-text-2\"> Rodinná firma Interiéry Horyna s.r.o.\nbyla založena v&nbsp;roce 2007 panem Zdeňkem Horynou, který od té doby prošel\ndlouhou cestu&nbsp;vysněných realizací interiérů.</p>\n                  <p class=\"u-text u-text-3\"> Nedílnou součástí naší firmy je také team zkušených a spolehlivých\nzaměstnanců, pro které je jejich práce koníčkem.</p>\n                  <p class=\"u-text u-text-4\"> V&nbsp;roce 2022 jsme vystavěli nový\na moderní showroom s&nbsp;výrobní halou, kde Vás velmi rádi přivítáme, poradíme\na navrhneme váš projekt.</p>\n                  <p class=\"u-text u-text-5\"> Naše široká škála služeb zahrnuje\nnejen podlahářské práce a výrobu vestavěného nábytku, ale také vnitřní a\nvenkovní stínící techniky, interiérových dveří, kování a mnoho dalšího.</p>\n                </div>\n              </div>\n              <div class=\"u-container-style u-image u-layout-cell u-size-26-lg u-size-26-xl u-size-60-md u-size-60-sm u-size-60-xs u-image-1\" data-image-width=\"1155\" data-image-height=\"866\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"250\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/IMG_1871.jpeg&quot;);\">\n                <div class=\"u-container-layout u-container-layout-3\"></div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </section>\n    \n    \n    \n  \n'),(516,92,'_np_html','<!DOCTYPE html>\n<html style=\"font-size: 16px;\"><head>\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <meta charset=\"utf-8\">\n    <meta name=\"keywords\" content=\"​A Leader in Solar, ​Energy Freedom with Solar&nbsp;and Storage, ​Simplified project development for a complex world, ​Make solar project development easier from start to finish, Why we should be greening our homes with plants, ​Energy Freedom with Solar and Storage, ​Help change the world, Get In Touch\"><meta name=\"description\" content=\"\"><meta name=\"page_type\" content=\"np-template-header-footer-from-plugin\">\n    <title></title>\n    <link rel=\"stylesheet\" href=\"//capp.nicepage.com/eef5851c6a60a800bcae9cceeea3f547dc0330ed/nicepage.css\" media=\"screen\">\n    <script class=\"u-script\" type=\"text/javascript\" src=\"//capp.nicepage.com/assets/jquery-1.9.1.min.js\" defer=\"\"></script>\n    <script class=\"u-script\" type=\"text/javascript\" src=\"//capp.nicepage.com/eef5851c6a60a800bcae9cceeea3f547dc0330ed/nicepage.js\" defer=\"\"></script>\n<meta name=\"generator\" content=\"Nicepage 5.17.1, nicepage.c