s:8:\"keywords\";a:0:{}}}'),(1464,95,'rank_math_internal_links_processed',1),(1465,1,'rank_math_internal_links_processed',1),(1466,2,'rank_math_internal_links_processed',1),(1467,3,'rank_math_internal_links_processed',1),(1468,57,'rank_math_internal_links_processed',1),(1469,39,'rank_math_internal_links_processed',1),(1470,43,'rank_math_internal_links_processed',1),(1471,38,'rank_math_internal_links_processed',1),(1472,42,'rank_math_internal_links_processed',1),(1473,37,'rank_math_internal_links_processed',1),(1475,36,'rank_math_internal_links_processed',1),(1476,35,'rank_math_internal_links_processed',1),(1477,34,'rank_math_internal_links_processed',1),(1478,262,'_np_template','html'),(1479,262,'rank_math_internal_links_processed',1),(1480,262,'_np_publish_html','\n    \n    <section class=\"u-align-center u-clearfix u-valign-top-xs u-white u-section-2\" id=\"carousel_12c9\">\n      <h2 class=\"u-align-center u-text u-text-1\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\">Dřevoplastové terasy</h2>\n      <p class=\"u-align-center u-text u-text-2\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"1500\" data-animation-delay=\"500\"> Dřevoplastové terasové prkno je inovativním řešením\npro ty, kteří hledají spojení estetiky dřeva a praktičnosti plastu. Tento\nmateriál je vytvořen smícháním dřevěných vláken nebo pilin s recyklovaným\nplastem, což vytváří odolný a ekologicky šetrný produkt</p>\n      <div class=\"data-layout-selected u-clearfix u-expanded-width u-layout-wrap u-layout-wrap-1\">\n        <div class=\"u-layout\">\n          <div class=\"u-layout-col\">\n            <div class=\"u-size-30\">\n              <div class=\"u-layout-row\">\n                <div class=\"u-container-align-center u-container-style u-image u-layout-cell u-size-30 u-image-1\" data-image-width=\"1200\" data-image-height=\"851\" data-animation-name=\"customAnimationIn\" data-animation-duration=\"2000\" data-animation-delay=\"250\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/1-DSC_0017.jpeg&quot;);\">\n                  <div class=\"u-container-layout u-container-layout-1\"></div>\n                </div>\n                <div class=\"u-container-align-left u-container-style u-layout-cell u-size-30 u-white u-layout-cell-2\">\n                  <div class=\"u-container-layout u-container-layout-2\">\n                    <h4 class=\"u-align-left u-text u-text-3\"> Dřevoplastové terasové desky mají několik výhod: </h4>\n                    <p class=\"u-align-left u-text u-text-4\">\n                      <span style=\"font-weight: 700;\"> Trvanlivost</span>: Dřevoplastové desky jsou odolné vůči\npovětrnostním vlivům, plísním, hnilobě a škůdcům. Nemusíte se obávat praskání,\nodbarvování nebo deformací. \n                    </p>\n                    <p class=\"u-align-left u-text u-text-5\">\n                      <span style=\"font-weight: 700;\"> Minimální údržba</span>: Tyto desky vyžadují minimální údržbu.\nNepotřebují pravidelné lakování nebo impregnaci, jako je tomu u tradičního\ndřeva. Stačí jen občasné čištění vodou a mýdlem. \n                    </p>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <p class=\"u-align-left u-text u-text-6\">\n                      <span style=\"font-weight: 700;\">Estetická přitažlivost:</span> Dřevoplastové terasové desky\npřinášejí do prostředí krásu přírodního dřeva, ale s větší konzistencí v barvě\na vzoru. Jsou k dispozici různá provedení, takže si můžete vybrat ten, který\nbude ladit s Vaším stylem.&nbsp;&nbsp;\n                    </p>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                    <editor-squiggler style=\"height: 0px; width: 0px;\">\n                      <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n                      <div class=\"ms-editor-squiggler\"></div>\n                    </editor-squiggler>\n                  </div>\n                </div>\n              </div>\n            </div>\n            <div class=\"u-size-30\">\n              <div class=\"u-layout-row\">\n 