       </thead>\n            <tbody class=\"u-table-alt-grey-5 u-table-body\">\n              <tr style=\"height: 75px;\">\n                <td class=\"u-border-1 u-border-grey-30 u-first-column u-grey-50 u-table-cell u-table-cell-3\"> Vratná kauce</td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\">5.000,- Kč</td>\n              </tr>\n              <tr style=\"height: 76px;\">\n                <td class=\"u-border-1 u-border-grey-30 u-first-column u-grey-50 u-table-cell u-table-cell-5\"> Denní půjčovné</td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\"> 500,- Kč</td>\n              </tr>\n              <tr style=\"height: 76px;\">\n                <td class=\"u-border-1 u-border-grey-30 u-first-column u-grey-50 u-table-cell u-table-cell-7\"> Tableta RM 760</td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\"> 35,- Kč /ks</td>\n              </tr>\n            </tbody>\n          </table>\n        </div>\n      </div>\n    </section>\n    <section class=\"u-clearfix u-section-4\" id=\"sec-316e\">\n      <div class=\"u-clearfix u-sheet u-valign-middle u-sheet-1\">\n        <h3 class=\"u-text u-text-1\">Příslušenství</h3>\n        <ul class=\"u-text u-text-2\">\n          <li>nástřiková a sací hadice 2,5m</li>\n          <li>podlahová hubice s kovovou dýzou</li>\n          <li>ruční hubice na čalounění</li>\n          <li><b>firma neodpovídá za úraz způsobený čističem na koberce\n(půjčení na vlastní nebezpečí)</b>&nbsp;\n          </li>\n          <li><b>v případě poškození stroje je vypůjčitel povinen\nuhradit vzniklou škodu</b>\n          </li>\n        </ul>\n      </div>\n    </section>\n    <section class=\"skrollable u-clearfix u-container-align-center u-image u-parallax u-section-5\" id=\"sec-cb17\" data-image-width=\"1600\" data-image-height=\"1600\" style=\"background-image: url(&quot;[[site_path_live]]/wp-content/uploads/2023/09/d0.jpeg&quot;);\">\n      <div class=\"u-clearfix u-sheet u-sheet-1\"></div>\n    </section>\n    <section class=\"u-clearfix u-section-6\" id=\"carousel_1f9b\">\n      <div class=\"u-clearfix u-sheet u-valign-middle u-sheet-1\">\n        <h3 class=\"u-text u-text-1\"> Zapůjčení brusných strojů</h3>\n        <ul class=\"u-text u-text-2\">\n          <li> válcová bruska BELT, okrajová\nbruska EDGE a talířová bruska BUFFER</li>\n        </ul>\n        <h4 class=\"u-text u-text-3\">Nájemné</h4>\n        <ul class=\"u-text u-text-4\">\n          <li>\n            <span style=\"font-weight: 700;\">Půldenní</span> – bruska je ráno zapůjčena a ještě týž den odpoledne vrácena\n&nbsp; &nbsp; &nbsp;\n          </li>\n          <li><!--[endif]-->\n            <span style=\"font-weight: 700;\">Denní</span> – bruska je ráno zapůjčena a druhý den ráno vrácena\n&nbsp; &nbsp; &nbsp;&nbsp;\n          </li>\n          <li><!--[endif]-->\n            <span style=\"font-weight: 700;\">Víkendové</span> – bruska je v pátek odpoledne zapůjčena a v pondělí ráno vrácena\n          </li>\n        </ul>\n        <editor-squiggler style=\"height: 0px; width: 0px;\">\n          <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n          <div class=\"ms-editor-squiggler\"></div>\n        </editor-squiggler>\n      </div>\n    </section>\n    <section class=\"u-align-center u-clearfix u-section-7\" id=\"carousel_e5bd\">\n      <div class=\"u-clearfix u-sheet u-valign-middle u-sheet-1\">\n        <div class=\"u-expanded-width u-table u-table-responsive u-table-1\">\n          <editor-squiggler style=\"height: 0px; width: 0px;\">\n            <style> @media print {\n    .ms-editor-squiggler {\n        display:none !important;\n    }\n  }\n  .ms-editor-squiggler {\n    all: initial;\n    display: block !important;\n    height: 0px !important;\n    width: 0px !important;\n  }</style>\n            <div class=\"ms-editor-squiggler\"></div>\n          </editor-squiggler>\n          <table class=\"u-table-entity u-table-entity-1\">\n            <colgroup>\n              <col width=\"25.1%\">\n              <col width=\"25.1%\">\n              <col width=\"24.8%\">\n              <col width=\"25%\">\n            </colgroup>\n            <thead class=\"u-black u-table-header u-table-header-1\">\n              <tr style=\"height: 21px;\">\n                <th class=\"u-border-1 u-border-black u-table-cell\"> Typ brusky&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</th>\n                <th class=\"u-border-1 u-border-black u-table-cell\"> Půldenní</th>\n                <th class=\"u-border-1 u-border-black u-table-cell\">Denní</th>\n                <th class=\"u-border-1 u-border-black u-table-cell\">Víkend</th>\n              </tr>\n            </thead>\n            <tbody class=\"u-table-alt-grey-5 u-table-body\">\n              <tr style=\"height: 75px;\">\n                <td class=\"u-border-1 u-border-grey-30 u-first-column u-grey-50 u-table-cell u-table-cell-5\"> Válcová bruska&nbsp;<span style=\"font-weight: 700;\">BELT</span>\n                </td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\"> 610 Kč</td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\">1.000 Kč</td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\">1.700\n  Kč</td>\n              </tr>\n              <tr style=\"height: 76px;\">\n                <td class=\"u-border-1 u-border-grey-30 u-first-column u-grey-50 u-table-cell u-table-cell-9\"> Okrajová bruska&nbsp;<span style=\"font-weight: 700;\">EDGE</span>&nbsp;\n                </td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\"> 400 Kč</td>\n                <td class=\"u-border-1 u-border-grey-30 u-table-cell\">450 K